namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public string Code { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public string DepartmentName { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }
}

namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Abbreviation { get; set; } = string.Empty;
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Name is required.")]
    [StringLength(100)]
    public string StudentName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^\d{6,10}$", ErrorMessage = "Student ID must be 6-10 digits.")]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments =
    [
        new() { Id = 1, Name = "Computer Science", Abbreviation = "CS" },
        new() { Id = 2, Name = "Mathematics", Abbreviation = "MATH" },
        new() { Id = 3, Name = "Physics", Abbreviation = "PHYS" },
        new() { Id = 4, Name = "English", Abbreviation = "ENG" },
        new() { Id = 5, Name = "History", Abbreviation = "HIST" },
    ];

    private readonly List<Course> _courses;

    public CatalogService()
    {
        _courses =
        [
            new() { Id = 1, Code = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using C#. Topics include variables, control flow, data structures, and object-oriented design.", Credits = 3, Schedule = "MWF 9:00–9:50 AM", InstructorName = "Dr. Alice Chen", InstructorBio = "Dr. Chen has 15 years of experience in software engineering and computer science education. She holds a Ph.D. from MIT.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 2, Code = "CS 201", Title = "Data Structures & Algorithms", Description = "Study of fundamental data structures (arrays, trees, graphs, hash tables) and algorithm design techniques including sorting, searching, and dynamic programming.", Credits = 4, Schedule = "TTh 10:30–11:45 AM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim specializes in algorithm optimization and has published extensively in ACM journals.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 3, Code = "CS 310", Title = "Database Systems", Description = "Relational database design, SQL, normalization, indexing strategies, and introduction to NoSQL systems.", Credits = 3, Schedule = "MWF 1:00–1:50 PM", InstructorName = "Dr. Maria Santos", InstructorBio = "Dr. Santos spent a decade at Oracle before joining academia. Her research focuses on distributed databases.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = false },
            new() { Id = 4, Code = "MATH 101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering.", Credits = 4, Schedule = "MWF 8:00–8:50 AM", InstructorName = "Prof. James Liu", InstructorBio = "Prof. Liu is an award-winning educator with a passion for making calculus accessible to all students.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = true },
            new() { Id = 5, Code = "MATH 201", Title = "Linear Algebra", Description = "Vector spaces, matrices, determinants, eigenvalues, and linear transformations with applications.", Credits = 3, Schedule = "TTh 2:00–3:15 PM", InstructorName = "Dr. Sarah Patel", InstructorBio = "Dr. Patel's research in applied mathematics bridges pure theory and computational methods.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false },
            new() { Id = 6, Code = "MATH 305", Title = "Probability & Statistics", Description = "Probability theory, random variables, distributions, hypothesis testing, and regression analysis.", Credits = 3, Schedule = "MWF 11:00–11:50 AM", InstructorName = "Dr. Sarah Patel", InstructorBio = "Dr. Patel's research in applied mathematics bridges pure theory and computational methods.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false },
            new() { Id = 7, Code = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes weekly lab sessions.", Credits = 4, Schedule = "MWF 10:00–10:50 AM + Lab Th 2:00–4:00 PM", InstructorName = "Dr. Thomas Grant", InstructorBio = "Dr. Grant is a former NASA researcher with expertise in astrophysics and classical mechanics.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = true },
            new() { Id = 8, Code = "PHYS 202", Title = "Electromagnetism", Description = "Electric and magnetic fields, Maxwell's equations, electromagnetic waves, and optics.", Credits = 4, Schedule = "TTh 9:00–10:15 AM + Lab W 3:00–5:00 PM", InstructorName = "Dr. Nina Volkov", InstructorBio = "Dr. Volkov's research in quantum optics has been published in Nature and Physical Review Letters.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = false },
            new() { Id = 9, Code = "ENG 101", Title = "English Composition", Description = "Develop clear, effective writing skills through essays, research papers, and peer review workshops.", Credits = 3, Schedule = "MWF 9:00–9:50 AM", InstructorName = "Prof. David Brooks", InstructorBio = "Prof. Brooks is a published author and has taught composition for over 20 years.", DepartmentId = 4, DepartmentName = "English", IsFeatured = false },
            new() { Id = 10, Code = "ENG 220", Title = "American Literature", Description = "Survey of major American literary works from the colonial period to the present.", Credits = 3, Schedule = "TTh 1:00–2:15 PM", InstructorName = "Dr. Emily Watson", InstructorBio = "Dr. Watson specializes in 20th-century American fiction and has written two books on the Harlem Renaissance.", DepartmentId = 4, DepartmentName = "English", IsFeatured = false },
            new() { Id = 11, Code = "HIST 101", Title = "World History to 1500", Description = "Survey of world civilizations from prehistory through the Renaissance, covering political, social, and cultural developments.", Credits = 3, Schedule = "MWF 2:00–2:50 PM", InstructorName = "Dr. Michael Torres", InstructorBio = "Dr. Torres is a specialist in ancient Mediterranean civilizations and archaeological methods.", DepartmentId = 5, DepartmentName = "History", IsFeatured = false },
            new() { Id = 12, Code = "HIST 250", Title = "Modern European History", Description = "Europe from the Enlightenment through the 21st century: revolutions, world wars, and the European Union.", Credits = 3, Schedule = "TTh 11:00 AM–12:15 PM", InstructorName = "Dr. Karen O'Brien", InstructorBio = "Dr. O'Brien has published widely on the political history of modern Europe and EU governance.", DepartmentId = 5, DepartmentName = "History", IsFeatured = true },
        ];
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetAllCourses() => _courses;

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public List<Course> GetCoursesByDepartment(int departmentId) =>
        _courses.Where(c => c.DepartmentId == departmentId).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }
}

