@page "/"
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>University Course Catalog</PageTitle>

<div class="container mt-4">
    <div class="text-center mb-5">
        <h1 class="display-4">University Course Catalog</h1>
        <p class="lead text-muted">Explore our departments and find the right courses for your academic journey.</p>
        <a href="/courses" class="btn btn-primary btn-lg mt-2">Browse All Courses</a>
    </div>

    <section class="mb-5">
        <h2>Featured Courses</h2>
        <div class="row">
            @foreach (var course in featuredCourses)
            {
                <div class="col-md-6 col-lg-4 mb-3">
                    <div class="card h-100">
                        <div class="card-body">
                            <h5 class="card-title">@course.Code</h5>
                            <h6 class="card-subtitle mb-2 text-muted">@course.Title</h6>
                            <p class="card-text small">@course.Credits credits &middot; @course.DepartmentName</p>
                            <a href="/courses/@course.Id" class="btn btn-outline-primary btn-sm">View Details</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    </section>

    <section>
        <h2>Departments</h2>
        <div class="row">
            @foreach (var dept in departments)
            {
                <div class="col-md-4 col-lg-3 mb-3">
                    <a href="/courses?departmentId=@dept.Id" class="text-decoration-none">
                        <div class="card text-center h-100">
                            <div class="card-body">
                                <h5 class="card-title">@dept.Abbreviation</h5>
                                <p class="card-text">@dept.Name</p>
                            </div>
                        </div>
                    </a>
                </div>
            }
        </div>
    </section>
</div>

@code {
    private List<UniversityCourseCatalog.Models.Course> featuredCourses = [];
    private List<UniversityCourseCatalog.Models.Department> departments = [];

    protected override void OnInitialized()
    {
        featuredCourses = CatalogService.GetFeaturedCourses();
        departments = CatalogService.GetDepartments();
    }
}

@page "/courses"
@rendermode InteractiveServer
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>Course Catalog – Browse Courses</PageTitle>

<div class="container mt-4">
    <h1>Browse Courses</h1>

    <div class="row mb-4">
        <div class="col-md-6">
            <input type="text" class="form-control" placeholder="Search by title, code, or instructor..."
                   @bind="searchTerm" @bind:event="oninput" />
        </div>
        <div class="col-md-4">
            <select class="form-select" @bind="selectedDepartmentId">
                <option value="0">All Departments</option>
                @foreach (var dept in departments)
                {
                    <option value="@dept.Id">@dept.Name</option>
                }
            </select>
        </div>
    </div>

    @if (filteredCourses.Count == 0)
    {
        <div class="alert alert-info">No courses match your search criteria.</div>
    }
    else
    {
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>Code</th>
                    <th>Title</th>
                    <th>Department</th>
                    <th>Credits</th>
                    <th>Instructor</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var course in filteredCourses)
                {
                    <tr>
                        <td>@course.Code</td>
                        <td>@course.Title</td>
                        <td>@course.DepartmentName</td>
                        <td>@course.Credits</td>
                        <td>@course.InstructorName</td>
                        <td><a href="/courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                    </tr>
                }
            </tbody>
        </table>
    }
</div>

@code {
    private string searchTerm = string.Empty;
    private int selectedDepartmentId;
    private List<UniversityCourseCatalog.Models.Course> filteredCourses = [];
    private List<UniversityCourseCatalog.Models.Department> departments = [];

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
        FilterCourses();
    }

    private string SearchTerm
    {
        get => searchTerm;
        set { searchTerm = value; FilterCourses(); }
    }

    private int SelectedDepartmentId
    {
        get => selectedDepartmentId;
        set { selectedDepartmentId = value; FilterCourses(); }
    }

    private void FilterCourses()
    {
        filteredCourses = CatalogService.SearchCourses(
            string.IsNullOrWhiteSpace(searchTerm) ? null : searchTerm,
            selectedDepartmentId > 0 ? selectedDepartmentId : null);
    }
}

@page "/enroll"
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>Enrollment Request – Course Catalog</PageTitle>

<div class="container mt-4">
    <h1>Enrollment Request</h1>
    <p class="text-muted">Submit your enrollment request below. You will receive confirmation via your university email.</p>

    @if (submitted)
    {
        <div class="alert alert-success">
            <h4>Request Submitted!</h4>
            <p>Thank you, <strong>@Model.StudentName</strong>. Your enrollment request for
                <strong>@selectedCourseName</strong> has been received.</p>
            <a href="/courses" class="btn btn-primary">Browse More Courses</a>
        </div>
    }
    else
    {
        <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="EnrollmentForm" method="post">
            <DataAnnotationsValidator />
            <AntiforgeryToken />
            <ValidationSummary class="text-danger" />

            <div class="mb-3">
                <label for="studentName" class="form-label">Full Name</label>
                <InputText id="studentName" class="form-control" @bind-Value="Model.StudentName" />
                <ValidationMessage For="() => Model.StudentName" class="text-danger" />
            </div>

            <div class="mb-3">
                <label for="studentId" class="form-label">Student ID</label>
                <InputText id="studentId" class="form-control" @bind-Value="Model.StudentId" placeholder="e.g. 12345678" />
                <ValidationMessage For="() => Model.StudentId" class="text-danger" />
            </div>

            <div class="mb-3">
                <label for="courseSelect" class="form-label">Course</label>
                <InputSelect id="courseSelect" class="form-select" @bind-Value="Model.CourseId">
                    <option value="0">-- Select a course --</option>
                    @foreach (var course in courses)
                    {
                        <option value="@course.Id">@course.Code – @course.Title</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => Model.CourseId" class="text-danger" />
            </div>

            <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
            <a href="/courses" class="btn btn-outline-secondary ms-2">Cancel</a>
        </EditForm>
    }
</div>

@code {
    [SupplyParameterFromForm]
    private UniversityCourseCatalog.Models.EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery]
    private int? CourseId { get; set; }

    private List<UniversityCourseCatalog.Models.Course> courses = [];
    private bool submitted;
    private string selectedCourseName = string.Empty;

    protected override void OnInitialized()
    {
        courses = CatalogService.GetAllCourses();

        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        var course = CatalogService.GetCourse(Model.CourseId);
        selectedCourseName = course is not null ? $"{course.Code} – {course.Title}" : "Unknown";
        submitted = true;
    }
}

